valid.code:
-- `CREATE INDEX ON foo (bar)` lets PostgreSQL pick the name — `idxname` is
-- unset on the IndexStmt, so there is nothing for this rule to flag.
CREATE INDEX ON aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa (bar);

-- Identifier at the exact 63-byte boundary is fine.
CREATE TABLE aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa (
  id BIGSERIAL PRIMARY KEY
);

-- A user who compiled PostgreSQL with a larger NAMEDATALEN can raise `max`.
-- This identifier is 64 bytes — over the default 63 but under the override.
CREATE TABLE aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa (
  id BIGSERIAL PRIMARY KEY
);

CREATE TABLE users (
  id BIGSERIAL PRIMARY KEY,
  email TEXT NOT NULL,
  CONSTRAINT users_email_uniq UNIQUE (email)
);

CREATE INDEX idx_users_email ON users (email);

CREATE SCHEMA app;

CREATE SEQUENCE app.order_seq;

CREATE OR REPLACE FUNCTION app.touch_updated_at() RETURNS trigger AS $$ BEGIN RETURN new; END; $$ LANGUAGE plpgsql;

CREATE VIEW active_users AS SELECT id FROM users;

CREATE TRIGGER trg_users_touch BEFORE UPDATE ON users FOR EACH ROW EXECUTE FUNCTION app.touch_updated_at();

ALTER TABLE users RENAME TO accounts;

-- An unnamed constraint has no user-supplied name to compare against the limit;
-- PostgreSQL will generate one, separately covered by `require-named-constraint`.
ALTER TABLE items ADD CHECK (length(code) > 0);

CREATE TABLE items2 (
  id BIGSERIAL PRIMARY KEY,
  code TEXT,
  CHECK (length(code) > 0)
);

invalid.code:
CREATE TABLE users (
  id BIGSERIAL PRIMARY KEY,
  aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa TEXT
);

ALTER TABLE items
  ADD CONSTRAINT aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa
    CHECK (length(code) > 0);

CREATE TABLE items (
  id BIGSERIAL PRIMARY KEY,
  code TEXT,
  CONSTRAINT aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa CHECK (length(code) > 0)
);

-- With `max: 10`, the 11-byte table name `looong_table` exceeds the limit.
CREATE TABLE looong_table (
  id BIGSERIAL PRIMARY KEY
);

-- 22 instances of the 3-byte character '長' = 66 bytes, which is over the
-- 63-byte limit even though it is only 22 characters long. The rule must
-- count bytes, not characters.
CREATE TABLE "長長長長長長長長長長長長長長長長長長長長長長" (
  id BIGSERIAL PRIMARY KEY
);

-- 64-byte table name — one over the default 63-byte limit.
CREATE TABLE aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa (
  id BIGSERIAL PRIMARY KEY
);

CREATE TRIGGER aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa
  BEFORE INSERT ON items
  FOR EACH ROW EXECUTE FUNCTION noop();
